# Middleware to track requests and latency
@app.before_request
def before_request():
    request.start_time = REQUEST_LATENCY.labels(request.path).time()

@app.after_request
def after_request(response):
    REQUEST_COUNT.labels(request.method, request.path).inc()
    request.start_time()
    return response

